import{_ as o,c,o as l,ag as t}from"./chunks/framework.B-XtCDNB.js";const m=JSON.parse('{"title":"3.3. Semantic Analyzer","description":"","frontmatter":{},"headers":[],"relativePath":"contributor-guide/compiler-guide/03-00-the-vala-compiler/03-03-semantic-analyzer.md","filePath":"contributor-guide/compiler-guide/03-00-the-vala-compiler/03-03-semantic-analyzer.md","lastUpdated":1777399741000}'),d={name:"contributor-guide/compiler-guide/03-00-the-vala-compiler/03-03-semantic-analyzer.md"};function a(i,e,r,s,n,p){return l(),c("div",null,[...e[0]||(e[0]=[t('<h1 id="_3-3-semantic-analyzer" tabindex="-1">3.3. Semantic Analyzer <a class="header-anchor" href="#_3-3-semantic-analyzer" aria-label="Permalink to &quot;3.3. Semantic Analyzer&quot;">​</a></h1><h2 id="_3-3-1-attribute-processing" tabindex="-1">3.3.1. Attribute Processing <a class="header-anchor" href="#_3-3-1-attribute-processing" aria-label="Permalink to &quot;3.3.1. Attribute Processing&quot;">​</a></h2><p><code>Vala.Attribute</code> nodes have a name and a possibly empty list of key-value arguments. Some types of code tree nodes have as children a list of <code>Attribute</code> nodes. The attribute processor&#39;s purpose is to interpret the attributes which were parsed into the code tree.</p><p>Later in the compilation, the results of attribute processing will be used, for example the <code>CCode</code> attribute <code>cname</code> affects what function names are used in emitted C code.</p><p>All attributes except for <code>Conditional</code> are handled from <code>Vala.AttributeProcessor</code>. I don&#39;t know where and how the <code>Conditional</code> attribute is handled, but there is a function <code>ignore_node()</code> in <code>Vala.CodeContext</code>.</p><p><code>Vala.AttributeProcessor</code> is a <code>CodeVisitor</code> which simply calls the <code>process_attributes()</code> method on every namespace, class, struct, interface, enum, method, constructor, parameter, property, delegate, constant, field, and signal that it visits.</p><p>Inside the <code>process_attributes()</code> method of each of these objects, a series of string comparisons will be made to parse the attributes. If the attribute is called <code>CCode</code>, then the <code>process_ccode_attributes()</code> function will be called to parse the key-value pairs supplied.</p><div class="info custom-block"><p class="custom-block-title">TODO</p><p>Mention <code>Vala.Parser.set_attributes ()</code></p><p>Feel free to help: <a href="https://github.com/vala-lang/vala-docs" target="_blank" rel="noreferrer">Vala Docs Repository</a>.</p></div><p>Attributes Recognized by Vala</p><p>All <code>Vala.Symbol</code> (class, constant, delegate, enum, enum value, errordomain, field, interface, method, property, signal, struct):</p><ul><li><code>Deprecated</code><ul><li><code>since</code></li></ul></li></ul><p><code>Vala.Namespace</code></p><ul><li><code>CCode</code></li></ul><p><code>Vala.Class</code></p><ul><li><code>CCode</code></li><li><code>DBus</code></li><li><code>Compact</code></li><li><code>Immutable</code></li><li><code>ErrorBase</code></li></ul><p><code>Vala.Struct</code></p><ul><li><code>CCode</code></li><li><code>SimpleType</code></li><li><code>IntegerType</code></li><li><code>FloatingType</code></li><li><code>BooleanType</code></li><li><code>Immutable</code></li></ul><p><code>Vala.Interface</code></p><ul><li><code>CCode</code></li><li><code>DBus</code></li></ul><p><code>Vala.Enum</code></p><ul><li><code>CCode</code></li><li><code>Flags</code></li></ul><p><code>Vala.Method</code></p><ul><li><code>CCode</code></li><li><code>DBus</code></li><li><code>ReturnsModifiedPointer</code></li><li><code>FloatingReference</code></li><li><code>NoWrapper</code></li><li><code>NoReturn</code></li><li><code>ModuleInit</code></li></ul><p><code>Vala.CreationMethod</code></p><blockquote><p>Same as <code>Vala.Method</code> — this class inherits from <code>Method</code>.</p></blockquote><p><code>Vala.FormalParameter</code></p><ul><li><code>CCode</code></li></ul><p><code>Vala.Property</code></p><ul><li><code>CCode</code></li><li><code>DBus</code></li><li><code>NoAccessorMethod</code></li><li><code>Description</code><ul><li><code>nick</code></li><li><code>blurb</code></li></ul></li></ul><p><code>Vala.PropertyAccessor</code></p><ul><li><code>CCode</code></li></ul><p><code>Vala.Delegate</code></p><ul><li><code>CCode</code></li></ul><p><code>Vala.Constant</code></p><ul><li><code>CCode</code></li></ul><p><code>Vala.Field</code></p><ul><li><code>CCode</code></li></ul><p><code>Vala.Signal</code></p><ul><li><code>DBus</code></li><li><code>Signal</code></li><li><code>HasEmitter</code></li></ul>',39)])])}const h=o(d,[["render",a]]);export{m as __pageData,h as default};
